let temp = 19 + Math.random() * 11;
let airHum = 45 + Math.random() * 25;
let soil = 28 + Math.random() * 50;
let light = 150 + Math.random() * 850;
let wind = 1 + Math.random() * 16;
let reservoir = 40 + Math.random() * 60;

let pump = flow.get('pump') || false;
let fan = flow.get('fan') || false;
let vents = flow.get('vents') || 'open';

if (pump) {
    soil = Math.min(100, soil + 9);
    reservoir = Math.max(0, reservoir - 0.8);
} else {
    soil = Math.max(0, soil - 1.1);
}

if (fan) {
    temp = Math.max(10, temp - 1.3);
    airHum = Math.max(20, airHum - 2.0);
} else {
    temp = Math.min(45, temp + 0.6);
}

if (wind > 12) {
    vents = 'closed';
    fan = true;
} else if (wind < 8 && temp < 28) {
    vents = 'open';
}

if (soil < 35) {
    pump = true;
} else if (soil > 55) {
    pump = false;
}

if (temp > 27 || airHum > 80) {
    fan = true;
} else if (temp < 24 && airHum < 70) {
    fan = false;
}

flow.set('pump', pump);
flow.set('fan', fan);
flow.set('vents', vents);

msg.payload = {
    entity: 'serre',
    temperature: Number(temp.toFixed(1)),
    airHumidity: Number(airHum.toFixed(1)),
    soilMoisture: Number(soil.toFixed(1)),
    light: Math.round(light),
    wind: Number(wind.toFixed(1)),
    reservoir: Number(reservoir.toFixed(1)),
    pump: pump,
    fan: fan,
    vents: vents,
    ts: new Date().toISOString()
};
return msg;
